t.script:
                var routeData = ;
                var map = L.map('route-map');
                L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                    attribution: '© OpenStreetMap contributors',
                    maxZoom: 18,
                }).addTo(map);

                if (routeData.tasks && routeData.tasks.length) {
                    var bounds = [];
                    routeData.tasks.forEach(function(task) {
                        if (task.lat && task.lng) {
                            var marker = L.marker([task.lat, task.lng]).addTo(map);
                            marker.bindPopup(
                                '<div class="task-popup">' +
                                '<span class="order">#' + task.order + '</span> ' +
                                task.name + '<br/>' +
                                task.partner + '<br/>' +
                                task.category +
                                '</div>'
                            );
                            bounds.push([task.lat, task.lng]);
                        }
                    });
                    if (routeData.geometry && routeData.geometry.type === 'LineString') {
                        var coords = routeData.geometry.coordinates.map(function(c) {
                            return [c[1], c[0]];
                        });
                        L.polyline(coords, {color: '#4a90d9', weight: 4}).addTo(map);
                    }
                    if (bounds.length) {
                        map.fitBounds(bounds, {padding: [30, 30]});
                    }
                } else {
                    map.setView([59.9139, 10.7522], 10);
                }
